                    RETURN OLD;
                END IF;
            END;
            $$ LANGUAGE plpgsql;

            CREATE OR REPLACE FUNCTION sync_module_study_user_role_to_study_user_role()
            RETURNS TRIGGER AS $$
            BEGIN
                IF pg_trigger_depth() > 1 THEN
                    RETURN COALESCE(NEW, OLD);
                END IF;

                IF (TG_OP = 'INSERT') THEN
                    INSERT INTO study_user_role (
                        study_user_role_id, role_name, study_id, user_name, status_id, owner_id
                    )
                    VALUES (
                        NEW.study_user_role_id, NEW.role_name, NEW.study_id, NEW.user_name, NEW.status_id, NEW.owner_id
                    )
                    ON CONFLICT (study_user_role_id) DO UPDATE SET
                        role_name = EXCLUDED.role_name,
                        study_id = EXCLUDED.study_id,
                        user_name = EXCLUDED.user_name,
                        status_id = EXCLUDED.status_id,
                        owner_id = EXCLUDED.owner_id;
                    RETURN NEW;
                ELSIF (TG_OP = 'UPDATE') THEN
                    UPDATE study_user_role SET
                        role_name = NEW.role_name,
                        study_id = NEW.study_id,
                        user_name = NEW.user_name,
                        status_id = NEW.status_id,
                        owner_id = NEW.owner_id
                    WHERE study_user_role_id = OLD.study_user_role_id;
                    RETURN NEW;
                ELSIF (TG_OP = 'DELETE') THEN
                    DELETE FROM study_user_role WHERE study_user_role_id = OLD.study_user_role_id;
                    RETURN OLD;
                END IF;
            END;
            $$ LANGUAGE plpgsql;

            CREATE OR REPLACE FUNCTION sync_study_user_role_to_module_study_user_role()
            RETURNS TRIGGER AS $$
            BEGIN
                IF pg_trigger_depth() > 1 THEN
                    RETURN COALESCE(NEW, OLD);
                END IF;

                IF (TG_OP = 'INSERT') THEN
                    INSERT INTO module_study_user_role (
                        study_user_role_id, role_name, study_id, user_name, status_id, owner_id
                    )
                    VALUES (
                        NEW.study_user_role_id, NEW.role_name, NEW.study_id, NEW.user_name, NEW.status_id, NEW.owner_id
                    )
                    ON CONFLICT (study_user_role_id) DO UPDATE SET
                        role_name = EXCLUDED.role_name,
                        study_id = EXCLUDED.study_id,
                        user_name = EXCLUDED.user_name,
                        status_id = EXCLUDED.status_id,
                        owner_id = EXCLUDED.owner_id;
                    RETURN NEW;
                ELSIF (TG_OP = 'UPDATE') THEN
                    UPDATE module_study_user_role SET
                        role_name = NEW.role_name,
                        study_id = NEW.study_id,
                        user_name = NEW.user_name,
                        status_id = NEW.status_id,
                        owner_id = NEW.owner_id
                    WHERE study_user_role_id = OLD.study_user_role_id;
                    RETURN NEW;
                ELSIF (TG_OP = 'DELETE') THEN
                    DELETE FROM module_study_user_role WHERE study_user_role_id = OLD.study_user_role_id;
                    RETURN OLD;
                END IF;
            END;
            $$ LANGUAGE plpgsql;

            DROP TRIGGER IF EXISTS trg_sync_module_user_account ON module_user_account;
            CREATE TRIGGER trg_sync_module_user_account
            AFTER INSERT OR UPDATE OR DELETE ON module_user_account
            FOR EACH ROW EXECUTE FUNCTION sync_module_user_account_to_user_account();

            DROP TRIGGER IF EXISTS trg_sync_user_account_to_module ON user_account;
            CREATE TRIGGER trg_sync_user_account_to_module
            AFTER INSERT OR UPDATE OR DELETE ON user_account
            FOR EACH ROW EXECUTE FUNCTION sync_user_account_to_module_user_account();

            DROP TRIGGER IF EXISTS trg_sync_module_study_user_role ON module_study_user_role;
            CREATE TRIGGER trg_sync_module_study_user_role
            AFTER INSERT OR UPDATE OR DELETE ON module_study_user_role
            FOR EACH ROW EXECUTE FUNCTION sync_module_study_user_role_to_study_user_role();

            DROP TRIGGER IF EXISTS trg_sync_study_user_role_to_module ON study_user_role;
            CREATE TRIGGER trg_sync_study_user_role_to_module
            AFTER INSERT OR UPDATE OR DELETE ON study_user_role
            FOR EACH ROW EXECUTE FUNCTION sync_study_user_role_to_module_study_user_role();

changeSet.rollback:
DROP TRIGGER IF EXISTS trg_sync_user_account_to_module ON user_account;
DROP FUNCTION IF EXISTS sync_user_account_to_module_user_account();
DROP TRIGGER IF EXISTS trg_sync_study_user_role_to_module ON study_user_role;
DROP FUNCTION IF EXISTS sync_study_user_role_to_module_study_user_role();
